import React, { useState, useEffect, useRef, useCallback } from 'react';

const images = [
  '/images/login%201.jpg',
  '/images/login%202.jpg',
  '/images/chat%20screen%201.jpg',
  '/images/outcoming%201.jpg',
  '/images/outcoming%202.jpg',
];

function TechGlobeSection() {
  const [currentImage, setCurrentImage] = useState(0);
  const [showImage, setShowImage] = useState(true);
  const [activeVideo, setActiveVideo] = useState(0);
  const [showVideo, setShowVideo] = useState(true);
  const video1Ref = useRef(null);
  const video2Ref = useRef(null);

  // Image slideshow - preload all, only toggle visibility
  useEffect(() => {
    let t1, t2, t3;
    const run = () => {
      setShowImage(true);
      t1 = setTimeout(() => {
        setShowImage(false);
        t2 = setTimeout(() => {
          setCurrentImage(prev => (prev + 1) % images.length);
          t3 = setTimeout(() => setShowImage(true), 50);
        }, 500);
      }, 2000);
    };
    run();
    const iv = setInterval(run, 2800);
    return () => { clearInterval(iv); clearTimeout(t1); clearTimeout(t2); clearTimeout(t3); };
  }, []);

  // Video 1 ended -> fade to video 2
  const onVideo1End = useCallback(() => {
    setShowVideo(false);
    setTimeout(() => {
      setActiveVideo(1);
      setShowVideo(true);
      const v = video2Ref.current;
      if (v) { v.currentTime = 0; v.play().catch(() => {}); }
    }, 600);
  }, []);

  // Video 2 - cut at 4s -> back to video 1
  const onVideo2Time = useCallback(() => {
    const v = video2Ref.current;
    if (v && v.currentTime >= 4) {
      v.pause();
      setShowVideo(false);
      setTimeout(() => {
        setActiveVideo(0);
        setShowVideo(true);
        const v1 = video1Ref.current;
        if (v1) { v1.currentTime = 0; v1.play().catch(() => {}); }
      }, 600);
    }
  }, []);

  return (
    <section className="relative py-20 px-4 sm:px-6 lg:px-8 overflow-hidden bg-white">
      <style>{`
        @keyframes rvOpen {
          from { clip-path: inset(50% 50% 50% 50% round 16px); opacity: 0; }
          to { clip-path: inset(0% 0% 0% 0% round 16px); opacity: 1; }
        }
        @keyframes rvClose {
          from { clip-path: inset(0% 0% 0% 0% round 16px); opacity: 1; }
          to { clip-path: inset(50% 50% 50% 50% round 16px); opacity: 0; }
        }
      `}</style>

      <div className="relative max-w-6xl mx-auto">
        <div className="text-center mb-12">
          <h2 className="text-4xl font-bold text-gray-900 mb-4">Sản Phẩm Của Chúng Tôi</h2>
          <p className="text-gray-500 text-lg">Xem demo trực tiếp sản phẩm đã triển khai</p>
        </div>

        <div className="flex flex-col lg:flex-row gap-8 items-center justify-center" style={{ minHeight: '520px' }}>

          {/* Left - Videos */}
          <div className="w-full lg:w-3/5 flex items-center justify-center">
            {/* Video 1 - landscape 16:9 */}
            <div 
              className="relative rounded-2xl overflow-hidden shadow-2xl"
              style={{ 
                aspectRatio: '16/9', 
                width: '100%',
                background: '#000', 
                transition: 'opacity 0.5s',
                opacity: showVideo && activeVideo === 0 ? 1 : 0,
                position: activeVideo === 0 ? 'relative' : 'absolute',
                pointerEvents: activeVideo === 0 ? 'auto' : 'none',
              }}
            >
              <video
                ref={video1Ref}
                className="absolute inset-0 w-full h-full object-cover"
                autoPlay muted playsInline
                onEnded={onVideo1End}
                src="/videos/video%20laptop.mp4"
              />
            </div>

            {/* Video 2 - portrait 9:16 */}
            <div 
              className="relative rounded-2xl overflow-hidden shadow-2xl"
              style={{ 
                aspectRatio: '9/16',
                height: '500px',
                background: '#000', 
                transition: 'opacity 0.5s',
                opacity: showVideo && activeVideo === 1 ? 1 : 0,
                position: activeVideo === 1 ? 'relative' : 'absolute',
                pointerEvents: activeVideo === 1 ? 'auto' : 'none',
              }}
            >
              <video
                ref={video2Ref}
                className="absolute inset-0 w-full h-full object-cover"
                muted playsInline
                onTimeUpdate={onVideo2Time}
                src="/videos/send%20images.mp4"
              />
            </div>
          </div>

          {/* Right - Image slideshow (portrait) */}
          <div className="w-full lg:w-2/5 flex items-center justify-center">
            <div className="relative" style={{ width: '260px', height: '520px' }}>
              {images.map((src, index) => (
                <div
                  key={index}
                  style={{
                    position: 'absolute',
                    inset: 0,
                    animation: index === currentImage 
                      ? (showImage ? 'rvOpen 0.6s ease-out forwards' : 'rvClose 0.4s ease-in forwards')
                      : 'none',
                    opacity: index === currentImage ? undefined : 0,
                    pointerEvents: 'none',
                  }}
                >
                  <img
                    src={src}
                    alt={`Screenshot ${index + 1}`}
                    className="w-full h-full object-cover rounded-2xl shadow-lg"
                  />
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}

export default TechGlobeSection;
